  1	import React, { FC, MouseEventHandler, useCallback, useEffect, useState } from 'react';
  2	import { useNavigate } from 'react-router-dom-v5-compat';
  3	import { useImmer } from 'use-immer';
  4	
  5	import { TemplateModel, TemplateParameter, V1Template } from '@kubevirt-ui/kubevirt-api/console';
  6	import { isEqualObject } from '@kubevirt-utils/components/NodeSelectorModal/utils/helpers';
  7	import SidebarEditor from '@kubevirt-utils/components/SidebarEditor/SidebarEditor';
  8	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  9	import { isEmpty } from '@kubevirt-utils/utils/utils';
 10	import { k8sUpdate } from '@openshift-console/dynamic-plugin-sdk';
 11	import {
 12	  ActionGroup,
 13	  Alert,
 14	  AlertVariant,
 15	  Button,
 16	  Divider,
 17	  EmptyState,
 18	  Form,
 19	  PageSection,
 20	  PageSectionVariants,
 21	  Title,
 22	} from '@patternfly/react-core';
 23	
 24	import useEditTemplateAccessReview from '../../hooks/useIsTemplateEditable';
 25	
 26	import ParameterEditor from './ParameterEditor';
 27	
 28	import './template-parameters-page.scss';
 29	
 30	type TemplateParametersPageProps = {
 31	  obj?: V1Template;
 32	};
 33	
 34	const TemplateParametersPage: FC<TemplateParametersPageProps> = ({ obj: template }) => {
 35	  const { t } = useKubevirtTranslation();
 36	  const [editableTemplate, setEditableTemplate] = useImmer(template);
 37	
 38	  const { isTemplateEditable } = useEditTemplateAccessReview(template);
 39	  const navigate = useNavigate();
 40	  const [error, setError] = useState();
 41	  const [success, setSuccess] = useState(false);
 42	  const [loading, setLoading] = useState(false);
 43	
 44	  useEffect(() => setEditableTemplate(template), [setEditableTemplate, template]);
 45	  const goBack = useCallback(() => {
 46	    navigate(-1);
 47	  }, [navigate]);
 48	
 49	  if (isEmpty(editableTemplate?.parameters))
 50	    return <EmptyState>{t('No parameters found in this template.')}</EmptyState>;
 51	
 52	  const onParameterChange = (parameter: TemplateParameter) => {
 53	    setEditableTemplate(({ parameters: draftParameters }) => {
 54	      const parameterIndex = draftParameters.findIndex((p) => p.name === parameter.name);
 55	      draftParameters[parameterIndex] = parameter;
 56	    });
 57	  };
 58	
 59	  const parameters = editableTemplate.parameters;
 60	
 61	  const isSaveDisabled = isEqualObject(template.parameters, parameters);
 62	
 63	  const onSave: MouseEventHandler<HTMLButtonElement> = async (event) => {
 64	    event.preventDefault();
 65	    setLoading(true);
 66	    try {
 67	      await k8sUpdate({
 68	        data: editableTemplate,
 69	        model: TemplateModel,
 70	      });
 71	      setSuccess(true);
 72	    } catch (apiError) {
 73	      setError(apiError);
 74	    } finally {
 75	      setLoading(false);
 76	    }
 77	  };
 78	
 79	  return (
 80	    <PageSection className="template-parameters-page" variant={PageSectionVariants.light}>
 81	      <SidebarEditor
 82	        onChange={(newTemplate) => setEditableTemplate(newTemplate)}
 83	        resource={editableTemplate}
 84	      >
 85	        <Form className="template-parameters-page__form">
 86	          <Title headingLevel="h2">{t('Parameters')}</Title>
 87	
 88	          {parameters.map((parameter, index) => (
 89	            <>
 90	              <ParameterEditor
 91	                isEditDisabled={!isTemplateEditable}
 92	                key={parameter.name}
 93	                onChange={onParameterChange}
 94	                parameter={parameter}
 95	              />
 96	              {index !== parameters.length - 1 && <Divider />}
 97	            </>
 98	          ))}
 99	          {error && (
100	            <Alert isInline title={t('Error')} variant={AlertVariant.danger}>
101	              {error}
102	            </Alert>
103	          )}
104	
105	          {success && (
106	            <Alert isInline title={t('Success')} variant={AlertVariant.info}>
107	              {t('Parameters successfully edited')}
108	            </Alert>
109	          )}
110	          <ActionGroup className="pf-v6-c-form">
111	            <Button
112	              isDisabled={isSaveDisabled}
113	              isLoading={loading}
114	              onClick={onSave}
115	              type="submit"
116	              variant="primary"
117	            >
118	              {t('Save')}
119	            </Button>
120	            <Button onClick={goBack} type="button" variant="secondary">
121	              {t('Cancel')}
122	            </Button>
123	          </ActionGroup>
124	        </Form>
125	      </SidebarEditor>
126	    </PageSection>
127	  );
128	};
129	
130	export default TemplateParametersPage;

